namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string Title { get; set; } = string.Empty;
    public string CourseCode { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Student name is required.")]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollmentRequests = new();

    public CourseCatalogService()
    {
        _departments = new List<Department>
        {
            new Department { Id = 1, Name = "Computer Science", Code = "CS", Description = "Explore the foundations of computing, software engineering, and artificial intelligence." },
            new Department { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study pure and applied mathematics, from abstract algebra to statistical modeling." },
            new Department { Id = 3, Name = "Physics", Code = "PHYS", Description = "Investigate the fundamental laws governing matter, energy, and the universe." },
            new Department { Id = 4, Name = "English", Code = "ENGL", Description = "Develop critical reading, writing, and analytical skills through literature and composition." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new Course { Id = 1, DepartmentId = 1, Title = "Introduction to Programming", CourseCode = "CS 101", Description = "A beginner-friendly course covering fundamental programming concepts using Python. Topics include variables, control flow, functions, data structures, and object-oriented programming basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a Ph.D. in Computer Science from MIT and has over 15 years of experience teaching introductory programming. She is passionate about making computing accessible to all students.", IsFeatured = true },
            new Course { Id = 2, DepartmentId = 1, Title = "Data Structures and Algorithms", CourseCode = "CS 201", Description = "An intermediate course exploring essential data structures such as linked lists, trees, graphs, and hash tables, along with algorithm design and analysis techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Prof. James Rivera", InstructorBio = "Prof. Rivera is a former software engineer at Google who transitioned to academia. His research focuses on algorithm optimization and competitive programming pedagogy." },
            new Course { Id = 3, DepartmentId = 1, Title = "Artificial Intelligence", CourseCode = "CS 410", Description = "An advanced course covering the principles and techniques of artificial intelligence, including search algorithms, knowledge representation, machine learning, neural networks, and natural language processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Anika Patel", InstructorBio = "Dr. Patel is an AI researcher with publications in top conferences including NeurIPS and ICML. She previously led the machine learning team at a healthcare startup.", IsFeatured = true },
            new Course { Id = 4, DepartmentId = 1, Title = "Database Systems", CourseCode = "CS 340", Description = "Study relational database design, SQL, transaction processing, query optimization, and an introduction to NoSQL databases. Includes a hands-on project building a full-stack application.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a Ph.D. in Computer Science from MIT and has over 15 years of experience teaching introductory programming. She is passionate about making computing accessible to all students." },

            // Mathematics
            new Course { Id = 5, DepartmentId = 2, Title = "Calculus I", CourseCode = "MATH 151", Description = "An introduction to differential calculus covering limits, continuity, derivatives, and their applications to real-world problems in science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has authored two widely-used calculus textbooks. He emphasizes intuitive understanding alongside rigorous proof.", IsFeatured = true },
            new Course { Id = 6, DepartmentId = 2, Title = "Linear Algebra", CourseCode = "MATH 220", Description = "Study vector spaces, linear transformations, matrices, determinants, eigenvalues, and eigenvectors with applications to computer graphics, data science, and engineering.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Prof. Maria Gonzalez", InstructorBio = "Prof. Gonzalez specializes in applied linear algebra and numerical methods. She has consulted for NASA on trajectory computation projects." },
            new Course { Id = 7, DepartmentId = 2, Title = "Probability and Statistics", CourseCode = "MATH 360", Description = "Covers probability theory, random variables, distributions, hypothesis testing, regression analysis, and Bayesian inference with real-world data sets.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has authored two widely-used calculus textbooks. He emphasizes intuitive understanding alongside rigorous proof." },

            // Physics
            new Course { Id = 8, DepartmentId = 3, Title = "General Physics I", CourseCode = "PHYS 101", Description = "An introductory course in classical mechanics covering kinematics, Newton's laws, energy, momentum, rotational motion, and gravitation. Includes weekly laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Elena Vasquez", InstructorBio = "Dr. Vasquez is an experimental physicist whose research in condensed matter physics has been funded by the National Science Foundation. She brings real-world lab experience into the classroom." },
            new Course { Id = 9, DepartmentId = 3, Title = "Electromagnetism", CourseCode = "PHYS 230", Description = "Explore electric fields, magnetic fields, Maxwell's equations, electromagnetic waves, and optics. Combines theoretical derivations with hands-on experiments.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:15 PM + Lab Fri 1:00–3:50 PM", InstructorName = "Prof. David Okafor", InstructorBio = "Prof. Okafor is a theoretical physicist with expertise in quantum electrodynamics. He has published extensively on electromagnetic field theory and mentors graduate students in the physics department." },
            new Course { Id = 10, DepartmentId = 3, Title = "Quantum Mechanics", CourseCode = "PHYS 440", Description = "An advanced course introducing the principles of quantum mechanics including wave-particle duality, the Schrödinger equation, quantum states, operators, and applications to atomic and molecular systems.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Elena Vasquez", InstructorBio = "Dr. Vasquez is an experimental physicist whose research in condensed matter physics has been funded by the National Science Foundation. She brings real-world lab experience into the classroom.", IsFeatured = true },

            // English
            new Course { Id = 11, DepartmentId = 4, Title = "College Composition", CourseCode = "ENGL 101", Description = "Develop foundational writing skills through essays, research papers, and peer review workshops. Emphasis on clarity, argumentation, and proper citation practices.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Linda Nakamura", InstructorBio = "Prof. Nakamura is a published author and writing pedagogy specialist. She has directed university writing centers for over a decade and believes every student can become a confident writer." },
            new Course { Id = 12, DepartmentId = 4, Title = "American Literature", CourseCode = "ENGL 250", Description = "Survey major works of American literature from the colonial period to the present, examining themes of identity, freedom, and the American experience through novels, poetry, and essays.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is a literary scholar specializing in 20th-century American fiction. His book on the Harlem Renaissance was shortlisted for a National Book Critics Circle award.", IsFeatured = true },
            new Course { Id = 13, DepartmentId = 4, Title = "Creative Writing Workshop", CourseCode = "ENGL 310", Description = "A workshop-format course where students write and critique original fiction, poetry, and creative nonfiction. Focus on voice, narrative structure, and revision techniques.", Credits = 3, Schedule = "Wed 6:00–8:30 PM", InstructorName = "Prof. Linda Nakamura", InstructorBio = "Prof. Nakamura is a published author and writing pedagogy specialist. She has directed university writing centers for over a decade and believes every student can become a confident writer." }
        };
    }

    public List<Department> GetDepartments() => _departments.ToList();

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public string GetDepartmentName(int departmentId) =>
        _departments.FirstOrDefault(d => d.Id == departmentId)?.Name ?? "Unknown";

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollmentRequests.Add(request);
    }
}

