50.     public List<Course> GetCourses(string? searchTerm, int? departmentId)
51.     {
52.         var query = _courses.AsEnumerable();
53. 
54.         if (departmentId.HasValue && departmentId.Value > 0)
55.         {
56.             query = query.Where(c => c.DepartmentId == departmentId.Value);
57.         }
58. 
59.         if (!string.IsNullOrWhiteSpace(searchTerm))
60.         {
61.             var term = searchTerm.Trim();
62.             query = query.Where(c =>
63.                 c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
64.                 c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase));
65.         }
66. 
67.         return query.ToList();
68.     }
69. 
70.     public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
71. 
72.     public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
73. 
74.     public string GetDepartmentName(int departmentId) =>
75.         _departments.FirstOrDefault(d => d.Id == departmentId)?.Name ?? "Unknown";
76. 
