 @page "/enroll"
 @inject UniversityCourseCatalog.Services.CourseCatalogService CatalogService

 <PageTitle>Enroll</PageTitle>

 <h1>Course Enrollment</h1>

 @if (submitted)
 {
     <div class="alert alert-success">
         <h4>Enrollment request submitted!</h4>
         <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@CatalogService.GetCourse(Model.CourseId)?.Title</strong> has been received.</p>
         <a href="courses" class="btn btn-primary mt-2">Browse More Courses</a>
     </div>
 }
 else
 {
     <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment">
         <DataAnnotationsValidator />
         <ValidationSummary />
         <AntiforgeryToken />

         <div class="mb-3">
             <label for="studentName" class="form-label">Student Name</label>
             <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
             <ValidationMessage For="() => Model.StudentName" />
         </div>

         <div class="mb-3">
             <label for="studentId" class="form-label">Student ID</label>
             <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
             <ValidationMessage For="() => Model.StudentId" />
         </div>

         <div class="mb-3">
             <label for="courseId" class="form-label">Course</label>
             <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                 <option value="0">-- Select a course --</option>
                 @foreach (var course in courses)
                 {
                     <option value="@course.Id">@course.CourseCode — @course.Title</option>
                 }
             </InputSelect>
             <ValidationMessage For="() => Model.CourseId" />
         </div>

         <button type="submit" class="btn btn-primary">Submit Enrollment</button>
     </EditForm>
 }

 @code {
     [SupplyParameterFromQuery]
     public int? CourseId { get; set; }

     [SupplyParameterFromForm]
     public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

     private List<UniversityCourseCatalog.Models.Course> courses = new();
     private bool submitted;

     protected override void OnInitialized()
     {
         courses = CatalogService.GetCourses(null, null);

         if (CourseId.HasValue && CourseId.Value > 0 && Model.CourseId == 0)
         {
             Model.CourseId = CourseId.Value;
         }
     }

     private void HandleSubmit()
     {
         CatalogService.SubmitEnrollmentRequest(Model);
         submitted = true;
     }
 }

